// // This module generates a 6-bit pseudo-random binary sequence using an LFSR with the polynomial x^6 + x + 1. When rst_n is high, the LFSR resets to the value 6'b000001.
module lfsr(
    input clk,
    input rst_n,
    output reg [5:0] lfsr_out
);
    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            lfsr_out <= 6'b000001;
        end else begin
            lfsr_out <= {lfsr_out[4:0], lfsr_out[5] ^ lfsr_out[0]};
        end
    end
endmodule
